import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const p = ex.params.event || {};
  return {
    pod_name: p['event.kubernetes_pod_name'] || p['affected_entity_ids']?.[0] || 'unknown',
    namespace: p['event.kubernetes_namespace'] || 'default',
    cluster: 'dynakube',
    service: p['affected_entity_names']?.[0] || 'unknown',
    severity: p['event.category'] || 'ERROR',
    title: p['event.name'] || p['display_id'] || 'Pod failure',
    problem_id: p['event.id'] || p['display_id'] || '',
    timestamp: new Date().toISOString()
  };
}

import { execution } from '@dynatrace-sdk/automation-utils';

const PD_TOKEN = 'YOUR_PAGERDUTY_API_TOKEN';
const PD_SERVICE_ID = 'P5DXFI2';
const PD_FROM = 'nimish.mehta@partior.com';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const meta = await ex.result('extract_metadata');

  const res = await fetch('https://api.pagerduty.com/incidents', {
    method: 'POST',
    headers: {
      'Authorization': `Token token=${PD_TOKEN}`,
      'Content-Type': 'application/json',
      'From': PD_FROM
    },
    body: JSON.stringify({
      incident: {
        type: 'incident',
        title: `[${meta.severity}] ${meta.service} - ${meta.title}`,
        service: { id: PD_SERVICE_ID, type: 'service_reference' },
        urgency: 'high',
        incident_key: `DT_${meta.problem_id}`,
        body: { type: 'incident_body', details: `Pod: ${meta.pod_name}\nNamespace: ${meta.namespace}\nCluster: ${meta.cluster}\nAuto-remediation in progress via GitOps.` }
      }
    })
  });
  const data = await res.json();
  if (!res.ok) throw new Error(`PagerDuty ${res.status}: ${JSON.stringify(data)}`);
  return { incident_id: data.incident.id, incident_number: data.incident.incident_number, incident_url: data.incident.html_url, incident_key: `DT_${meta.problem_id}` };
}

import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const meta = await ex.result('extract_metadata');
  const t = (meta.title || '').toLowerCase();

  let action = 'pod_restart', detail = 'Delete pod; controller respawns it';
  if (t.includes('memory') || t.includes('oom')) { action = 'increase_memory'; detail = 'Patch memory limits +512Mi'; }
  else if (t.includes('cpu') || t.includes('saturat')) { action = 'scale_replicas'; detail = 'Scale deployment to 3 replicas'; }
  else if (t.includes('imagepull')) { action = 'manual_review'; detail = 'Image/registry issue — needs human review'; }

  return { remediation_action: action, remediation_detail: detail, auto_remediable: action !== 'manual_review', analysis_timestamp: new Date().toISOString() };
}

import { execution } from '@dynatrace-sdk/automation-utils';

const GH_TOKEN = 'YOUR_GITHUB_TOKEN';
const GH_OWNER = 'your-org';
const GH_REPO = 'eks-gitops';
const GH_BRANCH = 'main';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const meta = await ex.result('extract_metadata');
  const analysis = await ex.result('analyze_failure');
  const ts = new Date().toISOString().replace(/[:.]/g, '-');

  let manifest = '';
  if (analysis.remediation_action === 'pod_restart') {
    manifest = `apiVersion: batch/v1
kind: Job
metadata:
  name: restart-${meta.pod_name.slice(0,40)}
  namespace: ${meta.namespace}
  labels:
    remediation: "true"
    incident: "DT-${meta.problem_id}"
spec:
  ttlSecondsAfterFinished: 300
  template:
    spec:
      serviceAccountName: dynatrace-workflow
      restartPolicy: Never
      containers:
      - name: kubectl
        image: bitnami/kubectl:latest
        command: ["kubectl", "delete", "pod", "${meta.pod_name}", "-n", "${meta.namespace}", "--grace-period=30"]
`;
  } else if (analysis.remediation_action === 'scale_replicas') {
    manifest = `apiVersion: apps/v1
kind: Deployment
metadata:
  name: ${meta.service}
  namespace: ${meta.namespace}
spec:
  replicas: 3
`;
  } else if (analysis.remediation_action === 'increase_memory') {
    manifest = `# Kustomize patch — increase memory for ${meta.service}
apiVersion: apps/v1
kind: Deployment
metadata:
  name: ${meta.service}
  namespace: ${meta.namespace}
spec:
  template:
    spec:
      containers:
      - name: ${meta.service}
        resources:
          limits:
            memory: 1Gi
`;
  }

  const path = `remediation/${meta.service}/${ts}-${analysis.remediation_action}.yaml`;
  const res = await fetch(`https://api.github.com/repos/${GH_OWNER}/${GH_REPO}/contents/${path}`, {
    method: 'PUT',
    headers: { 'Authorization': `token ${GH_TOKEN}`, 'Accept': 'application/vnd.github.v3+json' },
    body: JSON.stringify({
      message: `[INCIDENT DT-${meta.problem_id}] ${analysis.remediation_action}: ${meta.service}

${analysis.remediation_detail}`,
      content: btoa(manifest),
      branch: GH_BRANCH
    })
  });
  const data = await res.json();
  if (!res.ok) throw new Error(`GitHub ${res.status}: ${JSON.stringify(data)}`);
  return { commit_sha: data.commit.sha, commit_url: data.commit.html_url, file_path: path };
}

import { execution } from '@dynatrace-sdk/automation-utils';

const ARGOCD_URL = 'https://argocd.your-domain.com';
const ARGOCD_TOKEN = 'YOUR_ARGOCD_TOKEN';
const ARGOCD_APP = 'eks-remediation';

export default async function ({ execution_id }) {
  const res = await fetch(`${ARGOCD_URL}/api/v1/applications/${ARGOCD_APP}/sync`, {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${ARGOCD_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ prune: false, dryRun: false })
  });
  const data = await res.json();
  if (!res.ok) throw new Error(`ArgoCD ${res.status}: ${JSON.stringify(data)}`);
  return { sync_started: true, app: ARGOCD_APP, phase: data.status?.sync?.status || 'requested' };
}

import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const meta = await ex.result('extract_metadata');

  for (let i = 0; i < 8; i++) {
    await sleep(30000);
    try {
      const problems = await problemsClient.getProblems({ problemSelector: `displayId("${meta.problem_id}")` });
      const open = (problems.problems || []).filter(p => p.status === 'OPEN');
      if (open.length === 0) return { remediation_successful: true, checks: i + 1, verified_at: new Date().toISOString() };
    } catch (e) { /* keep polling */ }
  }
  return { remediation_successful: false, checks: 8, verified_at: new Date().toISOString() };
}

import { execution } from '@dynatrace-sdk/automation-utils';

const PD_TOKEN = 'YOUR_PAGERDUTY_API_TOKEN';
const PD_FROM = 'nimish.mehta@partior.com';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const pd = await ex.result('create_pagerduty_incident');
  const verify = await ex.result('wait_and_verify');
  const commit = await ex.result('create_git_commit');

  const success = verify.remediation_successful;
  const res = await fetch(`https://api.pagerduty.com/incidents/${pd.incident_id}`, {
    method: 'PUT',
    headers: { 'Authorization': `Token token=${PD_TOKEN}`, 'Content-Type': 'application/json', 'From': PD_FROM },
    body: JSON.stringify({
      incident: {
        type: 'incident_reference',
        status: success ? 'resolved' : 'acknowledged',
        resolution: success ? `Auto-remediated via GitOps. Commit: ${commit.commit_url}` : undefined
      }
    })
  });
  if (!res.ok) throw new Error(`PagerDuty resolve failed: ${res.status}`);
  return { pagerduty_status: success ? 'resolved' : 'escalated', success };
}

