import { execution } from '@dynatrace-sdk/automation-utils';
import { eventsClient, EventIngestEventType } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);
  const meta = await ex.result('extract_metadata');
  const verify = await ex.result('wait_and_verify');
  const analysis = await ex.result('analyze_failure');

  await eventsClient.createEvent({ body: {
    eventType: EventIngestEventType.CustomInfo,
    title: `Auto-remediation ${verify.remediation_successful ? 'succeeded' : 'failed'}: ${meta.service}`,
    properties: {
      'remediation.action': analysis.remediation_action,
      'remediation.success': String(verify.remediation_successful),
      'remediation.pod': meta.pod_name,
      'remediation.namespace': meta.namespace,
      'remediation.problem_id': meta.problem_id
    }
  }});
  return { audit_logged: true };
}
